              <p class="text-sm font-medium text-slate-900">{entry.actor}</p>
              <p class="text-xs text-slate-500">{entry.timeLabel}</p>
            </div>
            <p class="text-sm text-slate-600">{entry.summary}</p>
          </li>
        {/each}
      </ul>

      <div class="rounded-2xl border border-dashed border-slate-200 p-4">
        <p class="text-sm text-slate-600">
          <Trans>
            Imported digest:
            <span>{@html htmlDigest}</span>
          </Trans>
        </p>
        <p>
          <Trans>
            Also we can embed {"some text"} and {@html "<em>some HTML</em>"} directly
            in translations.
          </Trans>
        </p>
        <div>
          <Trans>
            <p>Maybe we even have some nested content to summarize, like</p>
            <ul>
              <li>
                <em>{highlightedQueue.length} highlighted queue items</em> and
              </li>
              <li>a selected region of {selectedRegion}.</li>
            </ul>
          </Trans>
        </div>
      </div>
    </div>

    <aside
      class="grid gap-4 rounded-3xl border border-slate-200 bg-white p-5 shadow-sm"
    >
      <h2 class="text-xl font-semibold text-slate-950">
        {$translate`Status digest`}
      </h2>
      <Plural
        value={$highlightedQueue.length}
        one={$translate`There is one highlighted queue item.`}
        other={$translate(
          msg`There are ${String($highlightedQueue.length)} highlighted queue items.`,
        )}
      />
      <p class="text-sm text-slate-600">
        {$translate(
          msg`The queue is ${String(filteredQueue.length > 8 ? "very busy" : "manageable")} and ${String($highlightedQueue.length > 2 ? "requires escalation" : "is within normal review limits")}.`,
        )}
      </p>
      <p class="text-sm text-slate-600">
        {$translate(
          msg`Nested expression summary: ${String(
            $highlightedQueue.length > 0
              ? `highlighted:${$highlightedQueue[0]?.id ?? "none"}`
              : `region:${selectedRegion}`,
          )}.`,
        )}
      </p>
    </aside>
  </section>
</div>
